/** Thailand Post item id for scanners: 13 chars, typically WB + 9 digits + TH (e.g. WB222126989TH). */
function parcelScanText(p: ParcelRow): string {
  return p.barcode?.trim() || p.trackingId.trim() || "";
}

function formatThaiDateTime(value: string) {
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return "-";
  const datePart = date.toLocaleDateString("th-TH", {
    day: "2-digit",
    month: "2-digit",
    year: "numeric",
  });
  const timePart = date.toLocaleTimeString("th-TH", {
    hour: "2-digit",
    minute: "2-digit",
    hour12: false,
  });
  return `${datePart} ${timePart} น.`;
}

export function ParcelsListClient({
  items,
  error,
  initialQuery = "",
}: {
  items: ParcelRow[];
  error: string | null;
  initialQuery?: string;
}) {
  const [query, setQuery] = useState(initialQuery);
  const [activeStatus, setActiveStatus] = useState<string>("all");
  const [copiedId, setCopiedId] = useState<string | null>(null);
  const [placeholderModal, setPlaceholderModal] = useState<{
    parcelCode: string;
  } | null>(null);
  const [scanModalMedia, setScanModalMedia] = useState<{
    barcode: string | null;
    loading: boolean;
    error: string | null;
  }>({ barcode: null, loading: false, error: null });
  const [expandedParcelId, setExpandedParcelId] = useState<string | null>(null);
  const [weightInfoParcelId, setWeightInfoParcelId] = useState<string | null>(null);
  const [simulatingParcelId, setSimulatingParcelId] = useState<string | null>(null);
  const [simulateMessage, setSimulateMessage] = useState<string | null>(null);
  const normalizedQuery = query.trim().toLowerCase();
  const devToolsEnabled = process.env.NEXT_PUBLIC_SMARTPOST_MOCK === "1";

  const toggleParcelExpanded = (parcelId: string) => {
    setExpandedParcelId((cur) => (cur === parcelId ? null : parcelId));
  };

  useEffect(() => {
    if (!placeholderModal) {
      setScanModalMedia({ barcode: null, loading: false, error: null });
      return;
    }
    const text = placeholderModal.parcelCode.trim();
    if (!text || text === "-") {
      setScanModalMedia({
        barcode: null,
        loading: false,
        error: "ไม่มีเลขพัสดุสำหรับสร้างบาร์โค้ด",
      });
      return;
    }
    let cancelled = false;
    setScanModalMedia({ barcode: null, loading: true, error: null });
    (async () => {
      try {
        const barcode = await parcelBarcodeDataUrl(text);
        if (!cancelled) {
          setScanModalMedia({ barcode, loading: false, error: null });
        }
      } catch {
        if (!cancelled) {
          setScanModalMedia({
            barcode: null,
            loading: false,
            error: "สร้างบาร์โค้ดไม่สำเร็จ",
          });
        }
      }
    })();
    return () => {
      cancelled = true;
    };
  }, [placeholderModal]);

  const statusTabs = useMemo(() => {
    const seen = new Set<string>();
    const tabs: string[] = [];
    for (const item of items) {
      const st = resolveListParcelStatus(item);
      if (seen.has(st)) continue;
      seen.add(st);
      tabs.push(st);
    }
    return tabs;
  }, [items]);

  const filteredItems = useMemo(() => {
    return items.filter((p) => {
      const st = resolveListParcelStatus(p);
      const statusMatched = activeStatus === "all" || st === activeStatus;
      if (!statusMatched) return false;
      if (!normalizedQuery) return true;
      const tracking = p.trackingId.toLowerCase();
      const barcode = (p.barcode ?? "").toLowerCase();
      return tracking.includes(normalizedQuery) || barcode.includes(normalizedQuery);
    });
  }, [items, normalizedQuery, activeStatus]);
  const awaitingForDev = useMemo(
    () => filteredItems.find((p) => resolveListParcelStatus(p) === "awaiting_actual_weight"),
    [filteredItems],
  );
  const hasSearch = normalizedQuery.length > 0;
  const copyTracking = async (parcelId: string, text: string) => {
    try {
      await navigator.clipboard.writeText(text);
      setCopiedId(parcelId);
      window.setTimeout(() => {
        setCopiedId((current) => (current === parcelId ? null : current));
      }, 1200);
    } catch {
      // Ignore clipboard failure silently; UI remains usable.
    }
  };

  const simulatePricingEstimate = async (parcelId: string, barcode: string | null) => {
    if (simulatingParcelId) return;
    setSimulateMessage(null);
    setSimulatingParcelId(parcelId);
    try {
      const res = await fetch("/api/dev/pricing-estimate", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ parcelId }),
      });
      const json = (await res.json().catch(() => ({}))) as { ok?: boolean; error?: string };
      if (!res.ok || !json.ok) {
        setSimulateMessage(json.error ?? "จำลองชั่งน้ำหนักไม่สำเร็จ");
        return;
      }
      setSimulateMessage(`จำลองสำเร็จ: ${barcode ?? parcelId} กำลังรีเฟรช...`);
      window.location.reload();
    } catch {
      setSimulateMessage("เครือข่ายผิดพลาด");
    } finally {
      setSimulatingParcelId(null);
    }
  };

  return (
    <div className="mx-auto w-full max-w-lg space-y-3">
      <div className="mb-5 rounded-lg bg-white p-3 shadow-sm ring-1 ring-slate-200">
        <label className="sr-only" htmlFor="parcel-search">
          ค้นหาเลขพัสดุหรือบาร์โค้ด
        </label>
        <div className="relative flex items-center gap-2">
          <span className="pointer-events-none absolute left-3 text-slate-400" aria-hidden>
            <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" fill="none" viewBox="0 0 24 24">
              <circle cx="11" cy="11" r="7" stroke="currentColor" strokeWidth="2" />
              <path d="m20 20-3.5-3.5" stroke="currentColor" strokeWidth="2" strokeLinecap="round" />
            </svg>
          </span>
          <input
            id="parcel-search"
            type="text"
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            placeholder="ค้นหา Tracking number / Barcode"
            className="h-10 w-full rounded-lg border border-slate-300 bg-white pl-9 pr-3 text-sm text-slate-800 outline-none placeholder:text-slate-400"
          />
          {hasSearch ? (
            <button
              type="button"
              onClick={() => setQuery("")}
              aria-label="ล้างคำค้นหา"
              className="inline-flex h-10 w-10 shrink-0 items-center justify-center rounded-lg border border-slate-300 text-slate-500 transition hover:bg-slate-50 hover:text-slate-700"
            >
              <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" fill="none" viewBox="0 0 24 24" aria-hidden>
                <path d="M6 6l12 12M18 6 6 18" stroke="currentColor" strokeWidth="2" strokeLinecap="round" />
              </svg>
            </button>
          ) : null}
        </div>
        <div className="mt-3 overflow-x-auto pb-1 [scrollbar-width:none] [&::-webkit-scrollbar]:hidden">
          <div className="inline-flex min-w-max items-center gap-2 whitespace-nowrap">
            <button
              type="button"
              onClick={() => setActiveStatus("all")}
              className={`shrink-0 rounded-full px-3 py-1.5 text-xs font-medium transition ${
                activeStatus === "all"
                  ? "bg-[#2726F5] text-white"
                  : "border border-slate-300 bg-white text-slate-700"
              }`}
            >
              ทั้งหมด
            </button>
            {statusTabs.map((status) => (
              <button
                key={status}
                type="button"
                onClick={() => setActiveStatus(status)}
                className={`shrink-0 rounded-full px-3 py-1.5 text-xs font-medium transition ${
                  activeStatus === status
                    ? "bg-[#2726F5] text-white"
                    : "border border-slate-300 bg-white text-slate-700"
                }`}
              >
                {getStatusLabel(status)}
              </button>
            ))}
          </div>
        </div>
      </div>

      {error ? (
        <div className="rounded-2xl border border-rose-200 bg-rose-50 px-4 py-3 text-sm font-medium text-rose-800">
          {error}
        </div>
      ) : null}

      {filteredItems.map((p) => {
        const isExpanded = expandedParcelId === p.id;
        const listStatus = resolveListParcelStatus(p);
          const showPaymentInfo =
            listStatus === "awaiting_actual_weight" || shouldShowPayButton(p) || p.isPaid;
        return (
        <article
          key={p.id}
          onClick={() => toggleParcelExpanded(p.id)}
          className="relative cursor-pointer overflow-visible rounded-lg bg-white py-5 shadow-sm ring-1 ring-slate-200 transition hover:ring-slate-300"
        >
          <div className="flex gap-2 px-5 pr-3">
            <div className="min-w-0 flex-1">
              <div className="min-w-0">
                <div className="grid grid-cols-[auto_1fr] items-center gap-x-4">
                  <span
                    className={`row-span-2 inline-flex h-10 w-10 shrink-0 items-center justify-center self-center rounded-full ${getStatusIconCircleClass(
                      resolveListParcelStatus(p),
                    )}`}
                    aria-label={getStatusLabel(resolveListParcelStatus(p))}
                    title={getStatusLabel(resolveListParcelStatus(p))}
                  >
                    <StatusCircleIcon status={resolveListParcelStatus(p)} />
                  </span>
                  <p className="min-w-0 text-xs font-normal text-slate-400">หมายเลขพัสดุ</p>
                  <div className="flex min-w-0 items-center gap-2">
                    <div className="min-w-0">
                      <p className="truncate text-xl font-medium leading-tight ">
                        {p.barcode ?? "-"}
                      </p>
                    </div>
                    <button
                      type="button"
                      onClick={(e) => {
                        e.stopPropagation();
                        void copyTracking(p.id, p.barcode ?? "-");
                      }}
                      aria-label="คัดลอกหมายเลขพัสดุ"
                      className="inline-flex h-6 w-6 shrink-0 items-center justify-center rounded-md text-slate-400 transition hover:bg-slate-100 hover:text-slate-600"
                    >
                      {copiedId === p.id ? (
                        <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" fill="none" viewBox="0 0 24 24" aria-hidden>
                          <path d="m5 13 4 4L19 7" stroke="#16A34A" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" />
                        </svg>
                      ) : (
                        <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" fill="none" viewBox="0 0 24 24" aria-hidden>
                          <rect x="9" y="3" width="12" height="14" rx="2" stroke="currentColor" strokeWidth="1.8" />
                          <rect x="3" y="7" width="12" height="14" rx="2" stroke="currentColor" strokeWidth="1.8" />
                        </svg>
                      )}
                    </button>
                  </div>
                </div>
              </div>

              <div className="mt-5 grid grid-cols-[1fr_auto_1fr] items-start gap-4 text-center">
                <div className="min-w-0">
                  <p className="truncate text-sm font-medium leading-tight text-slate-900">
                    {p.senderProvince ?? p.destination ?? "-"}
                  </p>
                  <p className="mt-1 truncate text-xs text-slate-500">{p.senderName ?? "-"}</p>
                  <p className="mt-1 truncate text-xs text-slate-400">{p.senderPhone ?? "-"}</p>
                </div>
                <div className="flex items-center justify-center pt-3">
                  <div className="flex w-full max-w-[220px] items-center gap-2">
                    <div className="h-px flex-1 bg-slate-200" />
                    <div className="flex shrink-0 flex-col items-center">
                      <span
                        className={`inline-flex rounded-full border px-2 py-[2px] text-[10px] font-medium ${getTimelineStatusClass(
                          resolveListParcelStatus(p),
                        )}`}
                      >
                        {getStatusLabel(resolveListParcelStatus(p))}
                      </span>
                      <p className="mt-1 text-[10px] font-normal text-slate-400">{formatThaiDateTime(p.createdAt)}</p>
                    </div>
                    <div className="h-px flex-1 bg-slate-200" />
                  </div>
                </div>
                <div className="min-w-0">
                  <p className="truncate text-sm font-medium leading-tight text-slate-900">
                    {p.recipientProvince ?? p.destination ?? "-"}
                  </p>
                  <p className="mt-1 truncate text-xs text-slate-500">{p.recipientName ?? "-"}</p>
                  <p className="mt-1 truncate text-xs text-slate-400">{p.recipientPhone ?? "-"}</p>
                </div>
              </div>
            </div>

            <div className="flex w-6 shrink-0 justify-center self-center">
              <button
                type="button"
                aria-expanded={isExpanded}
                aria-label={isExpanded ? "ย่อความคืบหน้า" : "ขยายดูความคืบหน้า"}
                onClick={(e) => {
                  e.stopPropagation();
                  toggleParcelExpanded(p.id);
                }}
                className="flex h-6 w-6 shrink-0 items-center justify-center rounded-full border border-slate-200 text-slate-400 outline-none transition hover:border-slate-300 hover:bg-slate-50 hover:text-slate-600 focus-visible:ring-2 focus-visible:ring-[#2726F5]/40"
              >
                <svg
                  xmlns="http://www.w3.org/2000/svg"
                  width="16"
                  height="16"
                  fill="none"
                  viewBox="0 0 24 24"
                  aria-hidden
                  className={`transition-transform duration-200 ${isExpanded ? "rotate-180" : ""}`}
                >
                  <path d="M6 9l6 6 6-6" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" />
                </svg>
              </button>
            </div>
          </div>

          <div className="mt-5 border-t border-slate-200 px-5 pt-4">
            <div className={`flex w-full min-w-0 items-center gap-3 ${showPaymentInfo ? "justify-between" : "justify-end"}`}>
            {listStatus === "awaiting_actual_weight" ? (
              <div className="relative min-w-0 flex-1">

                <span className="block text-xs font-normal leading-snug text-slate-700 line-clamp-2 break-words">
                  ชั่งพัสดุที่เคาน์เตอร์ไปรษณีย์ไทย
                </span>

                {weightInfoParcelId === p.id ? (
                  <div
                    className="absolute left-0 top-7 z-20 w-[280px] max-w-[calc(100vw-2.5rem)] rounded-lg border border-slate-200 bg-white p-3 text-xs text-slate-600 shadow-lg"
                    onClick={(e) => e.stopPropagation()}
                  >
                    กรุณานำพัสดุไปที่สถานีไปรษณีย์เพื่อชั่งน้ำหนักจริง เมื่อระบบได้รับน้ำหนักจริงแล้วจะแสดงยอดที่ต้องชำระให้ทันที
                  </div>
                ) : null}
              </div>
            ) : shouldShowPayButton(p) ? (
              <Link
                href={`/pay/${p.id}`}
                onClick={(e) => e.stopPropagation()}
                className="inline-flex min-w-0 max-w-full items-center gap-1 rounded-md bg-[#2726F5] px-4 py-2 text-xs font-medium text-white shadow-sm transition hover:bg-indigo-700 sm:flex-none sm:max-w-[calc(100%-7rem)]"
              >
                <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" fill="none" viewBox="0 0 24 24" className="shrink-0" aria-hidden>
                  <path d="M3 7h18v10H3V7Zm0 4h18" stroke="currentColor" strokeWidth="2" strokeLinecap="round" />
                </svg>
                <span className="truncate">ชำระเงิน {formatBaht(getOutstandingAmount(p))} บาท</span>
              </Link>
            ) : p.isPaid ? (
              <span className="flex min-w-0 max-w-full flex-1 items-center gap-1 truncate rounded-full py-1 text-xs font-medium text-teal-500 sm:flex-none sm:max-w-[calc(100%-7rem)]">
                <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" fill="currentColor" viewBox="0 0 16 16" className="shrink-0">
                  <path d="M2.5 8a5.5 5.5 0 0 1 8.25-4.764.5.5 0 0 0 .5-.866A6.5 6.5 0 1 0 14.5 8a.5.5 0 0 0-1 0 5.5 5.5 0 1 1-11 0"/>
                  <path d="M15.354 3.354a.5.5 0 0 0-.708-.708L8 9.293 5.354 6.646a.5.5 0 1 0-.708.708l3 3a.5.5 0 0 0 .708 0z"/>
                </svg>
                <span className="truncate">ชำระเงินสำเร็จแล้ว</span>
              </span>
            ) : null}
            <div className="flex shrink-0 items-center gap-4" onClick={(e) => e.stopPropagation()}>
              <Link
                href={`/parcels/${p.id}`}
                aria-label="ดูรายละเอียดพัสดุ"
                className="text-slate-400 transition hover:text-slate-600"
              >
                <svg xmlns="http://www.w3.org/2000/svg" width="22" height="22" fill="none" viewBox="0 0 24 24" aria-hidden>
                  <path
                    d="M1 12s4.5-7 11-7 11 7 11 7-4.5 7-11 7S1 12 1 12Z"
                    stroke="currentColor"
                    strokeWidth="1"
                    strokeLinecap="round"
                    strokeLinejoin="round"
                  />
                  <circle cx="12" cy="12" r="3" stroke="currentColor" strokeWidth="1" />
                </svg>
              </Link>
              <Link
                href={`/api/parcels/${p.id}/label.pdf`}
                target="_blank"
                rel="noopener noreferrer"
                aria-label="พิมพ์ใบปะหน้า"
                className="text-slate-400 transition hover:text-slate-600"
              >
                <svg xmlns="http://www.w3.org/2000/svg" width="22" height="22" fill="none" viewBox="0 0 24 24">
                  <path d="M7 8V4h10v4M7 16h10v4H7v-4Zm-2 0H4a1 1 0 0 1-1-1v-4a3 3 0 0 1 3-3h12a3 3 0 0 1 3 3v4a1 1 0 0 1-1 1h-1" stroke="currentColor" strokeWidth="1" strokeLinecap="round" strokeLinejoin="round" />
                </svg>
              </Link>
              <button
                type="button"
                aria-label="แสดงบาร์โค้ด"
                className="text-slate-400 transition hover:text-slate-600"
                onClick={(e) => {
                  e.stopPropagation();
                  setPlaceholderModal({
                    parcelCode: parcelScanText(p),
                  });
                }}
              >
                <svg xmlns="http://www.w3.org/2000/svg" width="22" height="22" fill="none" viewBox="0 0 24 24">
                  <path
                    d="M4 6v12M7 6v12M10 6v12M13 6v12M16 6v12M20 6v12M5 6h14M5 18h14"
                    stroke="currentColor"
                    strokeWidth="1"
                    strokeLinecap="round"
                  />
                </svg>
              </button>
            </div>
          </div>
          </div>

          {isExpanded ? (
            <div
              className="mt-4 w-full border-t border-slate-200 px-5 pt-4"
              onClick={(e) => e.stopPropagation()}
            >
              <ListParcelThaiPostProgressHorizontal
                parcel={{ ...p, status: resolveListParcelStatus(p), thaiPostEvents: p.thaiPostEvents }}
              />
              <Link
                href={`/parcels/${p.id}`}
                className="mt-3 inline-flex text-xs font-medium underline text-[#2726F5] hover:underline"
              >
                เปิดหน้ารายละเอียดพัสดุ
              </Link>
            </div>
          ) : null}
        </article>
        );
      })}

      {filteredItems.length === 0 && !error ? (
        <div className="rounded-lg bg-white p-5 text-center shadow-sm">
          {hasSearch ? (
            <>
              <p className="text-sm font-medium text-slate-700">ไม่พบพัสดุที่ค้นหา</p>
              <p className="mt-1 text-xs text-slate-500">ลองค้นหาด้วย Tracking number หรือ Barcode อื่น</p>
              <button
                type="button"
                onClick={() => setQuery("")}
                className="mt-3 inline-flex rounded-full border border-slate-300 px-4 py-2 text-xs font-medium text-slate-700"
              >
                ล้างการค้นหา
              </button>
            </>
          ) : (
            <>
              <p className="text-sm font-medium text-slate-700">ยังไม่มีพัสดุ</p>
              <p className="mt-1 text-xs text-slate-500">เริ่มสร้างรายการส่งพัสดุใหม่ได้ที่หน้าส่งพัสดุ</p>
              <SendLink className="mt-3 inline-flex rounded-full bg-[#2726F5] px-4 py-2 text-xs font-medium text-white">
                ไปหน้าส่งพัสดุ
              </SendLink>
            </>
          )}
        </div>
      ) : null}

      {devToolsEnabled ? (
        <div className="fixed bottom-[calc(env(safe-area-inset-bottom)+7.5rem)] right-4 z-50">
          <button
            type="button"
            disabled={simulatingParcelId !== null || !awaitingForDev}
            onClick={async () => {
              if (!awaitingForDev) return;
              await simulatePricingEstimate(awaitingForDev.id, awaitingForDev.barcode);
            }}
            className="inline-flex items-center rounded-full border border-amber-300 bg-amber-50 px-3 py-2 text-xs font-semibold text-amber-800 shadow-sm disabled:cursor-not-allowed disabled:opacity-50"
          >
            {simulatingParcelId !== null ? "[DEV] กำลังจำลอง..." : "[DEV] จำลองชั่งน้ำหนักจริง"}
          </button>
        </div>
      ) : null}
      {simulateMessage ? (
        <div className="fixed bottom-[calc(env(safe-area-inset-bottom)+5.5rem)] right-4 z-50 max-w-[280px] rounded-md bg-white px-2 py-1 text-[10px] text-slate-600 shadow ring-1 ring-slate-200">
          {simulateMessage}
        </div>
      ) : null}

      {placeholderModal ? (
        <div className="fixed inset-0 z-40 !mt-0 bg-black/40 px-6 py-10" onClick={() => setPlaceholderModal(null)}>
          <div
            className="mx-auto mt-24 w-full max-w-sm rounded-xl bg-white p-5 shadow-xl"
            onClick={(e) => e.stopPropagation()}
          >
            <h3 className="text-base font-semibold text-slate-900">BARCODE</h3>
            <p className="mt-1 text-xs text-slate-500">
              สแกนเพื่ออ่านเลขพัสดุ
            </p>
            <div className="mt-4 flex min-h-[11rem] items-center justify-center rounded-lg border border-slate-200 bg-white p-3">
              {scanModalMedia.loading ? (
                <span className="text-sm text-slate-500">กำลังสร้าง…</span>
              ) : scanModalMedia.error ? (
                <span className="px-2 text-center text-sm text-rose-600">{scanModalMedia.error}</span>
              ) : scanModalMedia.barcode ? (
                // eslint-disable-next-line @next/next/no-img-element -- data URL from jsbarcode
                <img src={scanModalMedia.barcode} alt="" className="max-h-52 w-full object-contain" />
              ) : null}
            </div>
            <p className="mt-3 text-xs text-slate-600">เลขพัสดุ: {placeholderModal.parcelCode || "—"}</p>
            <button
              type="button"
              className="mt-4 w-full rounded-lg bg-[#2726F5] px-4 py-2 text-sm font-medium text-white"
              onClick={() => setPlaceholderModal(null)}
            >
              ปิด
            </button>
          </div>
        </div>
      ) : null}
    </div>
  );
}
